  "header": {
    "title_primary": "{argument name=\"main chinese title\" default=\"业务影响\"}",
    "title_secondary": "{argument name=\"main english title\" default=\"Business Impact\"}",
    "tagline": "{argument name=\"tagline\" default=\"用数据说话，用结果证明价值\"}"
  },
  "layout": {
    "left_section": {
      "type": "折线图",
      "title": "效率与产能提升趋势",
      "y_axis": [
        "0%",
        "100%",
        "200%",
        "300%",
        "400%",
        "500%",
        "600%"
      ],
      "x_axis": [
        "Q1",
        "Q2",
        "Q3",
        "Q4",
        "现在"
      ],
      "lines": [
        {
          "label": "交付效率 (相对值)",
          "color": "霓虹蓝",
          "trend": "上升曲线",
          "annotation": "效率持续提升"
        },
        {
          "label": "单位成本 (相对值)",
          "color": "霓虹紫",
          "trend": "下降曲线",
          "annotation": "成本显著下降"
        }
      ]
    },
    "right_section": {
      "type": "KPI 网格",
      "count": 4,
      "arrangement": "2x2 网格",
      "cards": [
        {
          "icon": "火箭",
          "title": "效率提升",
          "value": "{argument name=\"kpi 1 value\" default=\"+120%\"}",
          "subtext": "交付效率显著提升"
        },
        {
          "icon": "带有向下箭头的硬币",
          "title": "成本降低",
          "value": "{argument name=\"kpi 2 value\" default=\"-200%\"}",
          "subtext": "单位交付成本下降"
        },
        {
          "icon": "带有向上箭头的柱状图",
          "title": "产能提升",
          "value": "5 倍",
          "subtext": "团队整体产能跃升"
        },
        {
          "icon": "人群",
          "title": "覆盖团队",
          "value": "10 个",
          "subtext": "业务团队规模化受益"
        }
      ]
    }
  }
}

